{
  "family": "Pinner Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "CCO"
    ],
    "product_smiles": [
      "CC(=[NH2+])OCC.[Cl-]"
    ],
    "optional_reagent_smiles": [
      "Cl"
    ],
    "rationale": "This reaction shows the formation of an imino ether hydrochloride salt (a Pinner salt) from a simple aliphatic nitrile (acetonitrile) and an alcohol (ethanol) in the presence of dry hydrogen chloride. This is the quintessential first step of the Pinner reaction, as described in textbooks. The product, ethyl acetimidate hydrochloride, is a stable, isolable intermediate characteristic of this transformation.",
    "collision_avoidance_note": "The use of simple, acyclic, saturated aliphatic substrates (acetonitrile, ethanol) avoids overlap with reactions involving aromatic rings, unsaturation, or complex functional groups. The explicit formation of the imino ether salt ([NH2+]) is a key feature that distinguishes it from simple nitrile hydrolysis or other nitrile additions. The reagent is specified as HCl gas (represented as 'Cl' for simplicity) to emphasize the anhydrous conditions required."
  }
}
